1	import {
2	  app,
3	  BrowserWindow,
4	  ipcMain,
5	  Menu,
6	  nativeTheme,
7	  session,
8	  shell,
9	} from "electron";
10	import contextMenu from "electron-context-menu";
11	import { IpcChannels, type SystemThemeVariant } from "../shared/ipc";
12	import { beginSignIn } from "./auth-flow";
13	import {
14	  getAuthSnapshot,
15	  getToken as getAuthToken,
16	  onAuthChanged,
17	  signOut as signOutAuth,
18	} from "./auth-store";
19	import { getBuildInfo } from "./build-info";
20	import { buildApplicationMenu } from "./menu";
21	import { getSentryInitOptions, initSentry } from "./sentry";
22	import {
23	  getSettings,
24	  onSettingsChanged,
25	  type SettingsSnapshot,
26	  updateSetting,
27	} from "./settings-store";
28	import {
29	  attachLocalShortcuts,
30	  registerGlobalShortcuts,
31	  unregisterGlobalShortcuts,
32	} from "./shortcuts";
33	import { createTray, destroyTray } from "./tray";
34	import { initUpdater, registerUpdaterIpc } from "./updater";
35	import { applyTitleBarOverlayTheme, createWindow } from "./windows/factory";
36	
37	declare const MAIN_WINDOW_VITE_DEV_SERVER_URL: string | undefined;
38	
39	const ALLOWED_EXTERNAL_PROTOCOLS = new Set(["http:", "https:", "mailto:"]);
40	
41	function currentThemeVariant(): SystemThemeVariant {
42	  return nativeTheme.shouldUseDarkColors ? "dark" : "light";
43	}
44	
45	function getApiOriginForCsp(): string {
46	  return (
47	    process.env.LIGHTFAST_API_URL ??
48	    (process.env.NODE_ENV === "production"
49	      ? "https://lightfast.ai"
50	      : "http://localhost:3024")
51	  );
52	}
53	
54	function getClerkFrontendApi(): string | null {
55	  const publishableKey = process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY;
56	  if (!publishableKey) {
57	    return null;
58	  }
59	  const base64Part = publishableKey.split("_")[2];
60	  if (!base64Part) {
61	    return null;
62	  }
63	  try {
64	    const domain = Buffer.from(base64Part, "base64")
65	      .toString("utf-8")
66	      .replace(/\$$/, "");
67	    if (!domain) {
68	      return null;
69	    }
70	    return `https://${domain}`;
71	  } catch {
72	    return null;
73	  }
74	}
75	
76	function buildContentSecurityPolicy(): string {
77	  const apiOrigin = getApiOriginForCsp();
78	  const clerkOrigin = getClerkFrontendApi();
79	  const extraConnect = [apiOrigin, clerkOrigin].filter(Boolean).join(" ");
80	
81	  const devServer = MAIN_WINDOW_VITE_DEV_SERVER_URL;
82	  if (devServer) {
83	    const origin = new URL(devServer).origin;
84	    const wsOrigin = origin.replace(/^http/, "ws");
85	    return [
86	      `default-src 'self' ${origin}`,
87	      `script-src 'self' 'unsafe-inline' ${origin}`,
88	      `style-src 'self' 'unsafe-inline' ${origin}`,
89	      `connect-src 'self' ${origin} ${wsOrigin} ${extraConnect}`.trim(),
90	      `img-src 'self' data: blob: ${origin}`,
91	      `font-src 'self' data: ${origin}`,
92	    ].join("; ");
93	  }
94	  return [
95	    "default-src 'self'",
96	    "script-src 'self'",
97	    "style-src 'self' 'unsafe-inline'",
98	    `connect-src 'self' ${extraConnect}`.trim(),
99	    "img-src 'self' data: blob:",
100	    "font-src 'self' data:",
101	  ].join("; ");
102	}
103	
104	function applyContentSecurityPolicy(): void {
105	  const csp = buildContentSecurityPolicy();
106	  session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
107	    callback({
108	      responseHeaders: {
109	        ...details.responseHeaders,
110	        "Content-Security-Policy": [csp],
111	      },
112	    });
113	  });
114	}
115	
116	function hardenContents(contents: Electron.WebContents): void {
117	  contents.setWindowOpenHandler(({ url }) => {
118	    try {
119	      const parsed = new URL(url);
120	      if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
121	        void shell.openExternal(url);
122	      }
123	    } catch {
124	      // ignore malformed urls
125	    }
126	    return { action: "deny" };
127	  });
128	
129	  contents.on("will-navigate", (event, url) => {
130	    const rendererOrigin = MAIN_WINDOW_VITE_DEV_SERVER_URL
131	      ? new URL(MAIN_WINDOW_VITE_DEV_SERVER_URL).origin
132	      : null;
133	    try {
134	      const target = new URL(url);
135	      if (rendererOrigin && target.origin === rendererOrigin) {
136	        return;
137	      }
138	      if (target.protocol === "file:") {
139	        return;
140	      }
141	      event.preventDefault();
142	      if (ALLOWED_EXTERNAL_PROTOCOLS.has(target.protocol)) {
143	        void shell.openExternal(url);
144	      }
145	    } catch {
146	      event.preventDefault();
147	    }
148	  });
149	}
150	
151	function registerIpcHandlers(): void {
152	  ipcMain.on(IpcChannels.getBuildInfoSync, (event) => {
153	    event.returnValue = getBuildInfo();
154	  });
155	
156	  ipcMain.on(IpcChannels.getSentryInitOptionsSync, (event) => {
157	    event.returnValue = getSentryInitOptions();
158	  });
159	
160	  ipcMain.on(IpcChannels.getSettingsSync, (event) => {
161	    event.returnValue = getSettings();
162	  });
163	
164	  ipcMain.handle(IpcChannels.updateSetting, (_event, payload: unknown) => {
165	    if (!payload || typeof payload !== "object") {
166	      return getSettings();
167	    }
168	    const { key, value } = payload as {
169	      key: keyof SettingsSnapshot;
170	      value: SettingsSnapshot[keyof SettingsSnapshot];
171	    };
172	    if (!(key in getSettings())) {
173	      return getSettings();
174	    }
175	    return updateSetting(key, value);
176	  });
177	
178	  ipcMain.handle(
179	    IpcChannels.getSystemThemeVariant,
180	    (): SystemThemeVariant => currentThemeVariant()
181	  );
182	
183	  ipcMain.handle(IpcChannels.openExternal, async (_event, url: unknown) => {
184	    if (typeof url !== "string") {
185	      return;
186	    }
187	    try {
188	      const parsed = new URL(url);
189	      if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
190	        await shell.openExternal(url);
191	      }
192	    } catch {
193	      // ignore malformed urls
194	    }
195	  });
196	
197	  ipcMain.on(IpcChannels.rendererError, (_event, payload: unknown) => {
198	    // eslint-disable-next-line no-console
199	    console.error("[renderer]", payload);
200	  });
201	
202	  ipcMain.handle(IpcChannels.openWindow, async (_event, kind: unknown) => {
203	    if (kind === "secondary") {
204	      await openSecondaryWindow();
205	    } else if (kind === "hud") {
206	      await openHudWindow();
207	    } else if (kind === "primary") {
208	      await openPrimaryWindow();
209	    }
210	  });
211	
212	  ipcMain.on(IpcChannels.authSnapshotSync, (event) => {
213	    event.returnValue = getAuthSnapshot();
214	  });
215	  ipcMain.handle(IpcChannels.authGetToken, () => getAuthToken());
216	  ipcMain.handle(IpcChannels.authSignIn, () => beginSignIn());
217	  ipcMain.handle(IpcChannels.authSignOut, () => {
218	    signOutAuth();
219	  });
220	}
221	
222	function broadcastThemeUpdates(): void {
223	  nativeTheme.on("updated", () => {
224	    const variant = currentThemeVariant();
225	    for (const win of BrowserWindow.getAllWindows()) {
226	      win.webContents.send(IpcChannels.systemThemeVariantUpdated, variant);
227	      applyTitleBarOverlayTheme(win);
228	    }
229	  });
230	}
231	
232	type Kind = "primary" | "secondary" | "hud";
233	
234	const windowsByKind = new Map<Kind, Set<BrowserWindow>>();
235	
236	function registerWindow(kind: Kind, win: BrowserWindow): void {
237	  const set = windowsByKind.get(kind) ?? new Set<BrowserWindow>();
238	  set.add(win);
239	  windowsByKind.set(kind, set);
240	  win.once("closed", () => {
241	    set.delete(win);
242	  });
243	}
244	
245	async function openKind(kind: Kind): Promise<BrowserWindow> {
246	  const win = await createWindow({ kind, harden: hardenContents });
247	  registerWindow(kind, win);
248	  attachLocalShortcuts(win);
249	  if (!app.isPackaged) {
250	    win.webContents.openDevTools({ mode: "detach" });
251	  }
252	  return win;
253	}
254	
255	export function openPrimaryWindow(): Promise<BrowserWindow> {
256	  return openKind("primary");
257	}
258	
259	export function openSecondaryWindow(): Promise<BrowserWindow> {
260	  return openKind("secondary");
261	}
262	
263	export function openHudWindow(): Promise<BrowserWindow> {
264	  return openKind("hud");
265	}
266	
267	function findWindow(kind: Kind): BrowserWindow | null {
268	  const set = windowsByKind.get(kind);
269	  if (!set) {
270	    return null;
271	  }
272	  for (const win of set) {
273	    if (!win.isDestroyed()) {
274	      return win;
275	    }
276	  }
277	  return null;
278	}
279	
280	function toggleHudWindow(): void {
281	  const existing = findWindow("hud");
282	  if (existing) {
283	    if (existing.isVisible()) {
284	      existing.hide();
285	    } else {
286	      existing.show();
287	      existing.focus();
288	    }
289	  } else {
290	    void openHudWindow();
291	  }
292	}
293	
294	const trayActions = {
295	  showPrimary: () => {
296	    const existing = findWindow("primary");
297	    if (existing) {
298	      existing.show();
299	      existing.focus();
300	    } else {
301	      void openPrimaryWindow();
302	    }
303	  },
304	  toggleHud: toggleHudWindow,
305	};
306	
307	function applySettings(snapshot: SettingsSnapshot): void {
308	  nativeTheme.themeSource = snapshot.themeSource;
309	  if (process.platform !== "linux" && app.isPackaged) {
310	    app.setLoginItemSettings({ openAtLogin: snapshot.launchAtLogin });
311	  }
312	  if (snapshot.showInMenuBar) {
313	    createTray(trayActions);
314	  } else {
315	    destroyTray();
316	  }
317	}
318	
319	function broadcastSettings(snapshot: SettingsSnapshot): void {
320	  for (const win of BrowserWindow.getAllWindows()) {
321	    win.webContents.send(IpcChannels.settingsChanged, snapshot);
322	  }
323	}
324	
325	initSentry();
326	
327	contextMenu({
328	  showInspectElement: !app.isPackaged,
329	  showSaveImageAs: true,
330	  showCopyImage: true,
331	  showSelectAll: true,
332	});
333	
334	app.whenReady().then(() => {
335	  applyContentSecurityPolicy();
336	  session.defaultSession.setPermissionRequestHandler(
337	    (_contents, _permission, callback) => {
338	      callback(false);
339	    }
340	  );
341	
342	  Menu.setApplicationMenu(
343	    buildApplicationMenu({
344	      openSecondary: () => {
345	        void openSecondaryWindow();
346	      },
347	      openHud: () => {
348	        void openHudWindow();
349	      },
350	    })
351	  );
352	
353	  registerIpcHandlers();
354	  registerUpdaterIpc();
355	  broadcastThemeUpdates();
356	  registerGlobalShortcuts({ toggleHud: toggleHudWindow });
357	  applySettings(getSettings());
358	  if (getSettings().checkForUpdatesAutomatically) {
359	    initUpdater();
360	  }
361	  onSettingsChanged((snapshot) => {
362	    applySettings(snapshot);
363	    broadcastSettings(snapshot);
364	  });
365	  void openPrimaryWindow();
366	
367	  onAuthChanged((snapshot) => {
