import * as Sentry from "@sentry/browser";
import { useQueryClient } from "@tanstack/react-query";
import { useEffect, useState } from "react";
import { Toaster, toast } from "sonner";
import type { AuthSnapshot } from "../../../shared/ipc";
import { AccountCard } from "./account-card";
import { SignedOutShell } from "./signed-out-shell";

let signoutFailureReported = false;

export function AppShell() {
  const [auth, setAuth] = useState<AuthSnapshot>(
    () => window.lightfastBridge.auth.snapshot
  );
  const queryClient = useQueryClient();

  useEffect(() => window.lightfastBridge.auth.onChanged(setAuth), []);

  useEffect(() => {
    const unsub = queryClient.getQueryCache().subscribe((event) => {
      if (event.type !== "updated") {
        return;
      }
      const err = event.query.state.error;
      if (!err) {
        return;
      }
      const code = (err as { data?: { code?: string } }).data?.code;
      if (code === "UNAUTHORIZED") {
        void window.lightfastBridge.auth.signOut().then((ok) => {
          if (!(ok || signoutFailureReported)) {
            signoutFailureReported = true;
            Sentry.captureException(new Error("auto-sign-out failed"), {
              tags: { scope: "app-shell.auto-sign-out" },
            });
          }
        });
      }
    });
    return unsub;
  }, [queryClient]);

  if (!auth.isSignedIn) {
    return (
      <>
        <Toaster />
        <SignedOutShell
          onLearnMore={() =>
            void window.lightfastBridge.openExternal("https://lightfast.ai")
          }
          onSignIn={() => void window.lightfastBridge.auth.signIn()}
        />
      </>
    );
  }

  return (
    <div>
      <Toaster />
      <AccountCard />
      <button
        onClick={() => {
          void window.lightfastBridge.auth.signOut().then((ok) => {
            if (!ok) {
              toast.error("Sign out failed — please try again");
            }
          });
        }}
        type="button"
      >
        Sign out
      </button>
    </div>
  );
}

import { randomBytes } from "node:crypto";
import { createServer, type Server } from "node:http";
import { shell } from "electron";
import { setToken } from "./auth-store";

const SIGNIN_TIMEOUT_MS = 5 * 60_000;
const LOOPBACK_HOST = "127.0.0.1";
const CALLBACK_PATH = "/callback";

function getApiOrigin(): string {
  return (
    process.env.LIGHTFAST_API_URL ??
    (process.env.NODE_ENV === "production"
      ? "https://lightfast.ai"
      : "http://localhost:3024")
  );
}

function responsePage(message: string): string {
  return `<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <title>Lightfast</title>
    <meta name="viewport" content="width=device-width,initial-scale=1" />
    <style>
      html, body { height: 100%; margin: 0; }
      body {
        display: flex; align-items: center; justify-content: center;
        font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
        background: #0a0a0a; color: #e5e5e5;
      }
      .card { text-align: center; padding: 2rem; max-width: 28rem; }
      h1 { font-size: 1.125rem; font-weight: 600; margin: 0 0 0.5rem; }
      p { color: #a3a3a3; margin: 0; font-size: 0.875rem; }
    </style>
  </head>
  <body>
    <div class="card">
      <h1>${message}</h1>
      <p>You can close this tab and return to Lightfast.</p>
    </div>
  </body>
</html>`;
}

async function startLoopbackServer(): Promise<{
  server: Server;
  port: number;
}> {
  const server = createServer();
  await new Promise<void>((resolve, reject) => {
    const onError = (error: Error) => {
      server.off("listening", onListening);
      reject(error);
    };
    const onListening = () => {
      server.off("error", onError);
      resolve();
    };
    server.once("error", onError);
    server.once("listening", onListening);
    server.listen(0, LOOPBACK_HOST);
  });
  const address = server.address();
  if (!address || typeof address !== "object") {
    server.close();
    throw new Error("loopback server failed to bind");
  }
  return { server, port: address.port };
}

export async function beginSignIn(): Promise<string | null> {
  const state = randomBytes(32).toString("hex");

  let bound: { server: Server; port: number };
  try {
    bound = await startLoopbackServer();
  } catch (error) {
    console.error("[auth-flow] loopback bind failed", error);
    return null;
  }
  const { server, port } = bound;
  const callbackUrl = `http://${LOOPBACK_HOST}:${port}${CALLBACK_PATH}`;

  return new Promise<string | null>((resolve) => {
    let settled = false;
    const settle = (token: string | null) => {
      if (settled) {
        return;
      }
      settled = true;
      clearTimeout(timer);
      server.close();
      resolve(token);
    };

    const timer = setTimeout(() => settle(null), SIGNIN_TIMEOUT_MS);

    server.on("request", (req, res) => {
      try {
        const url = new URL(req.url ?? "/", `http://${LOOPBACK_HOST}:${port}`);
        if (url.pathname !== CALLBACK_PATH) {
          res.writeHead(404, { "Content-Type": "text/plain" });
          res.end("Not Found");
          return;
        }
        const token = url.searchParams.get("token");
        const returned = url.searchParams.get("state");
        const valid = Boolean(token) && returned === state;
        if (!(valid && token)) {
          res.writeHead(400, { "Content-Type": "text/html" });
          res.end(responsePage("Sign-in failed"));
          settle(null);
          return;
        }
        const persisted = setToken(token);
        res.writeHead(persisted ? 200 : 500, { "Content-Type": "text/html" });
        res.end(
          responsePage(persisted ? "Signed in to Lightfast" : "Sign-in failed")
        );
        settle(persisted ? token : null);
      } catch (error) {
        console.error("[auth-flow] loopback handler error", error);
        res.writeHead(500, { "Content-Type": "text/plain" });
        res.end("Internal Server Error");
        settle(null);
      }
    });

    server.on("error", (error) => {
      console.error("[auth-flow] loopback server error", error);
      settle(null);
    });

    const signInUrl = new URL("/desktop/auth", getApiOrigin());
    signInUrl.searchParams.set("state", state);
    signInUrl.searchParams.set("callback", callbackUrl);

    console.log(
      `[auth-flow] signin url=${signInUrl.toString()} callback=${callbackUrl}`
    );

    shell.openExternal(signInUrl.toString()).catch((error) => {
      console.error("[auth-flow] shell.openExternal failed", error);
      settle(null);
    });
  });
}

import {
  app,
  BrowserWindow,
  ipcMain,
  Menu,
  nativeTheme,
  session,
  shell,
} from "electron";
import contextMenu from "electron-context-menu";
import { IpcChannels, type SystemThemeVariant } from "../shared/ipc";
import { beginSignIn } from "./auth-flow";
import {
  getAuthSnapshot,
  getToken as getAuthToken,
  onAuthChanged,
  signOut as signOutAuth,
} from "./auth-store";
import { getBuildInfo } from "./build-info";
import { buildApplicationMenu } from "./menu";
import { getSentryInitOptions, initSentry } from "./sentry";
import {
  getSettings,
  onSettingsChanged,
  type SettingsSnapshot,
  updateSetting,
} from "./settings-store";
import {
  attachLocalShortcuts,
  registerGlobalShortcuts,
  unregisterGlobalShortcuts,
} from "./shortcuts";
import { createTray, destroyTray } from "./tray";
import { initUpdater, registerUpdaterIpc } from "./updater";
import { applyTitleBarOverlayTheme, createWindow } from "./windows/factory";

declare const MAIN_WINDOW_VITE_DEV_SERVER_URL: string | undefined;

const ALLOWED_EXTERNAL_PROTOCOLS = new Set(["http:", "https:", "mailto:"]);

function currentThemeVariant(): SystemThemeVariant {
  return nativeTheme.shouldUseDarkColors ? "dark" : "light";
}

function getApiOriginForCsp(): string {
  return (
    process.env.LIGHTFAST_API_URL ??
    (process.env.NODE_ENV === "production"
      ? "https://lightfast.ai"
      : "http://localhost:3024")
  );
}

function getClerkFrontendApi(): string | null {
  const publishableKey = process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY;
  if (!publishableKey) {
    return null;
  }
  const base64Part = publishableKey.split("_")[2];
  if (!base64Part) {
    return null;
  }
  try {
    const domain = Buffer.from(base64Part, "base64")
      .toString("utf-8")
      .replace(/\$$/, "");
    if (!domain) {
      return null;
    }
    return `https://${domain}`;
  } catch {
    return null;
  }
}

function buildContentSecurityPolicy(): string {
  const apiOrigin = getApiOriginForCsp();
  const clerkOrigin = getClerkFrontendApi();
  const extraConnect = [apiOrigin, clerkOrigin].filter(Boolean).join(" ");

  const devServer = MAIN_WINDOW_VITE_DEV_SERVER_URL;
  if (devServer) {
    const origin = new URL(devServer).origin;
    const wsOrigin = origin.replace(/^http/, "ws");
    return [
      `default-src 'self' ${origin}`,
      `script-src 'self' 'unsafe-inline' ${origin}`,
      `style-src 'self' 'unsafe-inline' ${origin}`,
      `connect-src 'self' ${origin} ${wsOrigin} ${extraConnect}`.trim(),
      `img-src 'self' data: blob: ${origin}`,
      `font-src 'self' data: ${origin}`,
    ].join("; ");
  }
  return [
    "default-src 'self'",
    "script-src 'self'",
    "style-src 'self' 'unsafe-inline'",
    `connect-src 'self' ${extraConnect}`.trim(),
    "img-src 'self' data: blob:",
    "font-src 'self' data:",
  ].join("; ");
}

function applyContentSecurityPolicy(): void {
  const csp = buildContentSecurityPolicy();
  session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
    callback({
      responseHeaders: {
        ...details.responseHeaders,
        "Content-Security-Policy": [csp],
      },
    });
  });
}

function hardenContents(contents: Electron.WebContents): void {
  contents.setWindowOpenHandler(({ url }) => {
    try {
      const parsed = new URL(url);
      if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
        void shell.openExternal(url);
      }
    } catch {
      // ignore malformed urls
    }
    return { action: "deny" };
  });

  contents.on("will-navigate", (event, url) => {
    const rendererOrigin = MAIN_WINDOW_VITE_DEV_SERVER_URL
      ? new URL(MAIN_WINDOW_VITE_DEV_SERVER_URL).origin
      : null;
    try {
      const target = new URL(url);
      if (rendererOrigin && target.origin === rendererOrigin) {
        return;
      }
      if (target.protocol === "file:") {
        return;
      }
      event.preventDefault();
      if (ALLOWED_EXTERNAL_PROTOCOLS.has(target.protocol)) {
        void shell.openExternal(url);
      }
    } catch {
      event.preventDefault();
    }
  });
}

function registerIpcHandlers(): void {
  ipcMain.on(IpcChannels.getBuildInfoSync, (event) => {
    event.returnValue = getBuildInfo();
  });

  ipcMain.on(IpcChannels.getSentryInitOptionsSync, (event) => {
    event.returnValue = getSentryInitOptions();
  });

  ipcMain.on(IpcChannels.getSettingsSync, (event) => {
    event.returnValue = getSettings();
  });

  ipcMain.handle(IpcChannels.updateSetting, (_event, payload: unknown) => {
    if (!payload || typeof payload !== "object") {
      return getSettings();
    }
    const { key, value } = payload as {
      key: keyof SettingsSnapshot;
      value: SettingsSnapshot[keyof SettingsSnapshot];
    };
    if (!(key in getSettings())) {
      return getSettings();
    }
    return updateSetting(key, value);
  });

  ipcMain.handle(
    IpcChannels.getSystemThemeVariant,
    (): SystemThemeVariant => currentThemeVariant()
  );

  ipcMain.handle(IpcChannels.openExternal, async (_event, url: unknown) => {
    if (typeof url !== "string") {
      return;
    }
    try {
      const parsed = new URL(url);
      if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
        await shell.openExternal(url);
      }
    } catch {
      // ignore malformed urls
    }
  });

  ipcMain.on(IpcChannels.rendererError, (_event, payload: unknown) => {
    // eslint-disable-next-line no-console
    console.error("[renderer]", payload);
  });

  ipcMain.handle(IpcChannels.openWindow, async (_event, kind: unknown) => {
    if (kind === "secondary") {
      await openSecondaryWindow();
    } else if (kind === "hud") {
      await openHudWindow();
    } else if (kind === "primary") {
      await openPrimaryWindow();
    }
  });

  ipcMain.on(IpcChannels.authSnapshotSync, (event) => {
    event.returnValue = getAuthSnapshot();
  });
  ipcMain.handle(IpcChannels.authGetToken, () => getAuthToken());
  ipcMain.handle(IpcChannels.authSignIn, () => beginSignIn());
  ipcMain.handle(IpcChannels.authSignOut, () => signOutAuth());
}

function broadcastThemeUpdates(): void {
  nativeTheme.on("updated", () => {
    const variant = currentThemeVariant();
    for (const win of BrowserWindow.getAllWindows()) {
      win.webContents.send(IpcChannels.systemThemeVariantUpdated, variant);
      applyTitleBarOverlayTheme(win);
    }
  });
}

type Kind = "primary" | "secondary" | "hud";

const windowsByKind = new Map<Kind, Set<BrowserWindow>>();

function registerWindow(kind: Kind, win: BrowserWindow): void {
  const set = windowsByKind.get(kind) ?? new Set<BrowserWindow>();
  set.add(win);
  windowsByKind.set(kind, set);
  win.once("closed", () => {
    set.delete(win);
  });
}

async function openKind(kind: Kind): Promise<BrowserWindow> {
  const win = await createWindow({ kind, harden: hardenContents });
  registerWindow(kind, win);
  attachLocalShortcuts(win);
  if (!app.isPackaged) {
    win.webContents.openDevTools({ mode: "detach" });
  }
  return win;
}

export function openPrimaryWindow(): Promise<BrowserWindow> {
  return openKind("primary");
}

export function openSecondaryWindow(): Promise<BrowserWindow> {
  return openKind("secondary");
}

export function openHudWindow(): Promise<BrowserWindow> {
  return openKind("hud");
}

function findWindow(kind: Kind): BrowserWindow | null {
  const set = windowsByKind.get(kind);
  if (!set) {
    return null;
  }
  for (const win of set) {
    if (!win.isDestroyed()) {
      return win;
    }
  }
  return null;
}

function toggleHudWindow(): void {
  const existing = findWindow("hud");
  if (existing) {
    if (existing.isVisible()) {
      existing.hide();
    } else {
      existing.show();
      existing.focus();
    }
  } else {
    void openHudWindow();
  }
}

const trayActions = {
  showPrimary: () => {
    const existing = findWindow("primary");
    if (existing) {
      existing.show();
      existing.focus();
    } else {
      void openPrimaryWindow();
    }
  },
  toggleHud: toggleHudWindow,
};

function applySettings(snapshot: SettingsSnapshot): void {
  nativeTheme.themeSource = snapshot.themeSource;
  if (process.platform !== "linux" && app.isPackaged) {
    app.setLoginItemSettings({ openAtLogin: snapshot.launchAtLogin });
  }
  if (snapshot.showInMenuBar) {
    createTray(trayActions);
  } else {
    destroyTray();
  }
}

function broadcastSettings(snapshot: SettingsSnapshot): void {
  for (const win of BrowserWindow.getAllWindows()) {
    win.webContents.send(IpcChannels.settingsChanged, snapshot);
  }
}

initSentry();

contextMenu({
  showInspectElement: !app.isPackaged,
  showSaveImageAs: true,
  showCopyImage: true,
  showSelectAll: true,
});

app.whenReady().then(() => {
  applyContentSecurityPolicy();
  session.defaultSession.setPermissionRequestHandler(
    (_contents, _permission, callback) => {
      callback(false);
    }
  );

  Menu.setApplicationMenu(
    buildApplicationMenu({
      openSecondary: () => {
        void openSecondaryWindow();
      },
      openHud: () => {
        void openHudWindow();
      },
    })
  );

  registerIpcHandlers();
  registerUpdaterIpc();
  broadcastThemeUpdates();
  registerGlobalShortcuts({ toggleHud: toggleHudWindow });
  applySettings(getSettings());
  if (getSettings().checkForUpdatesAutomatically) {
    initUpdater();
  }
  onSettingsChanged((snapshot) => {
    applySettings(snapshot);
    broadcastSettings(snapshot);
  });
  void openPrimaryWindow();

  onAuthChanged((snapshot) => {
    for (const win of BrowserWindow.getAllWindows()) {
      win.webContents.send(IpcChannels.authChanged, snapshot);
    }
  });

  app.on("activate", () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      void openPrimaryWindow();
    }
  });
});

app.on("will-quit", () => {
  unregisterGlobalShortcuts();
  destroyTray();
});

app.on("web-contents-created", (_event, contents) => {
  hardenContents(contents);
});

app.on("window-all-closed", () => {
  if (process.platform !== "darwin") {
    app.quit();
  }
});

export const IPC_NAMESPACE = "lightfast_desktop";

const channel = (name: string) => `${IPC_NAMESPACE}:${name}` as const;

export const IpcChannels = {
  getSystemThemeVariant: channel("get-system-theme-variant"),
  systemThemeVariantUpdated: channel("system-theme-variant-updated"),
  openExternal: channel("open-external"),
  openWindow: channel("open-window"),
  getBuildInfoSync: channel("get-build-info-sync"),
  getSentryInitOptionsSync: channel("get-sentry-init-options-sync"),
  rendererError: channel("renderer-error"),
  updaterCheck: channel("updater-check"),
  updaterInstall: channel("updater-install"),
  updaterStatusSync: channel("updater-status-sync"),
  updaterStatusChanged: channel("updater-status-changed"),
  menuAction: channel("menu-action"),
  getSettingsSync: channel("get-settings-sync"),
  updateSetting: channel("update-setting"),
  settingsChanged: channel("settings-changed"),
  authSnapshotSync: channel("auth-snapshot-sync"),
  authGetToken: channel("auth-get-token"),
  authSignIn: channel("auth-sign-in"),
  authSignOut: channel("auth-sign-out"),
  authChanged: channel("auth-changed"),
} as const;

export type IpcChannel = (typeof IpcChannels)[keyof typeof IpcChannels];

export type SystemThemeVariant = "light" | "dark";

export type Platform =
  | "aix"
  | "android"
  | "darwin"
  | "freebsd"
  | "haiku"
  | "linux"
  | "openbsd"
  | "sunos"
  | "win32"
  | "cygwin"
  | "netbsd";

export type WindowKind = "primary" | "secondary" | "hud";

export interface BuildInfoSnapshot {
  buildFlavor: "dev" | "preview" | "prod";
  buildNumber: string;
  name: string;
  sparkleFeedUrl: string;
  sparklePublicKey: string;
  version: string;
}

export interface SentryInitSnapshot {
  dsn: string;
  enabled: boolean;
  environment: string;
  release: string;
}

export interface RendererErrorPayload {
  kind: "error" | "unhandledrejection";
  message: string;
  source?: string;
  stack?: string;
  url?: string;
}

export type UpdaterState =
  | "idle"
  | "checking"
  | "available"
  | "not-available"
  | "downloading"
  | "ready"
  | "error";

export interface UpdaterStatusSnapshot {
  message?: string;
  progress?: number;
  state: UpdaterState;
}

import type { AcceleratorName } from "./accelerators";

export type ThemeSource = "system" | "light" | "dark";

export interface SettingsSnapshot {
  checkForUpdatesAutomatically: boolean;
  launchAtLogin: boolean;
  showInMenuBar: boolean;
  themeSource: ThemeSource;
}

export interface AuthSnapshot {
  isSignedIn: boolean;
}

export interface LightfastBridge {
  auth: {
    snapshot: AuthSnapshot;
    getToken: () => Promise<string | null>;
    signIn: () => Promise<string | null>;
    signOut: () => Promise<boolean>;
    onChanged: (listener: (snapshot: AuthSnapshot) => void) => () => void;
  };
  buildInfo: BuildInfoSnapshot;
  getSystemThemeVariant: () => Promise<SystemThemeVariant>;
  onMenuAction: (listener: (action: AcceleratorName) => void) => () => void;
  onSettingsChanged: (
    listener: (snapshot: SettingsSnapshot) => void
  ) => () => void;
  onSystemThemeVariantUpdated: (
    listener: (variant: SystemThemeVariant) => void
  ) => () => void;
  onUpdaterStatusChanged: (
    listener: (status: UpdaterStatusSnapshot) => void
  ) => () => void;
  openExternal: (url: string) => Promise<void>;
  openWindow: (kind: WindowKind) => Promise<void>;
  platform: Platform;
  reportError: (payload: RendererErrorPayload) => void;
  sentryInit: SentryInitSnapshot;
  settings: SettingsSnapshot;
  updater: {
    status: UpdaterStatusSnapshot;
    check: () => Promise<{ ok: boolean; reason?: string }>;
    install: () => Promise<void>;
  };
  updateSetting: <K extends keyof SettingsSnapshot>(
    key: K,
    value: SettingsSnapshot[K]
  ) => Promise<SettingsSnapshot>;
}

