} from "electron";
import contextMenu from "electron-context-menu";
import { IpcChannels, type SystemThemeVariant } from "../shared/ipc";
import { beginSignIn } from "./auth-flow";
import { createAuthFocusGate } from "./auth-focus-gate";
import {
  getAuthSnapshot,
  getToken as getAuthToken,
  onAuthChanged,
  signOut as signOutAuth,
} from "./auth-store";
import { getBuildInfo } from "./build-info";
import { buildApplicationMenu } from "./menu";
import { getSentryInitOptions, initSentry } from "./sentry";
import {
  getSettings,
  onSettingsChanged,
  type SettingsSnapshot,
  updateSetting,
} from "./settings-store";
import {
  attachLocalShortcuts,
  registerGlobalShortcuts,
  unregisterGlobalShortcuts,
} from "./shortcuts";
import { createTray, destroyTray } from "./tray";
import { initUpdater, registerUpdaterIpc } from "./updater";
import { applyTitleBarOverlayTheme, createWindow } from "./windows/factory";

declare const MAIN_WINDOW_VITE_DEV_SERVER_URL: string | undefined;

const ALLOWED_EXTERNAL_PROTOCOLS = new Set(["http:", "https:", "mailto:"]);

function currentThemeVariant(): SystemThemeVariant {
  return nativeTheme.shouldUseDarkColors ? "dark" : "light";
}

function getApiOriginForCsp(): string {
  return (
    process.env.LIGHTFAST_API_URL ??
    (process.env.NODE_ENV === "production"
      ? "https://lightfast.ai"
      : "http://localhost:3024")
  );
}

function getClerkFrontendApi(): string | null {
  const publishableKey = process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY;
  if (!publishableKey) {
    return null;
  }
  const base64Part = publishableKey.split("_")[2];
  if (!base64Part) {
    return null;
  }
  try {
    const domain = Buffer.from(base64Part, "base64")
      .toString("utf-8")
      .replace(/\$$/, "");
    if (!domain) {
      return null;
    }
    return `https://${domain}`;
  } catch {
    return null;
  }
}

function buildContentSecurityPolicy(): string {
  const apiOrigin = getApiOriginForCsp();
  const clerkOrigin = getClerkFrontendApi();
  const extraConnect = [apiOrigin, clerkOrigin].filter(Boolean).join(" ");

  const devServer = MAIN_WINDOW_VITE_DEV_SERVER_URL;
  if (devServer) {
    const origin = new URL(devServer).origin;
    const wsOrigin = origin.replace(/^http/, "ws");
    return [
      `default-src 'self' ${origin}`,
      `script-src 'self' 'unsafe-inline' ${origin}`,
      `style-src 'self' 'unsafe-inline' ${origin}`,
      `connect-src 'self' ${origin} ${wsOrigin} ${extraConnect}`.trim(),
      `img-src 'self' data: blob: ${origin}`,
      `font-src 'self' data: ${origin}`,
    ].join("; ");
  }
  return [
    "default-src 'self'",
    "script-src 'self'",
    "style-src 'self' 'unsafe-inline'",
    `connect-src 'self' ${extraConnect}`.trim(),
    "img-src 'self' data: blob:",
    "font-src 'self' data:",
  ].join("; ");
}

function applyContentSecurityPolicy(): void {
  const csp = buildContentSecurityPolicy();
  session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
    callback({
      responseHeaders: {
        ...details.responseHeaders,
        "Content-Security-Policy": [csp],
      },
    });
  });
}

function hardenContents(contents: Electron.WebContents): void {
  contents.setWindowOpenHandler(({ url }) => {
    try {
      const parsed = new URL(url);
      if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
        void shell.openExternal(url);
      }
    } catch {
      // ignore malformed urls
    }
    return { action: "deny" };
  });

  contents.on("will-navigate", (event, url) => {
    const rendererOrigin = MAIN_WINDOW_VITE_DEV_SERVER_URL
      ? new URL(MAIN_WINDOW_VITE_DEV_SERVER_URL).origin
      : null;
    try {
      const target = new URL(url);
      if (rendererOrigin && target.origin === rendererOrigin) {
        return;
      }
      if (target.protocol === "file:") {
        return;
      }
      event.preventDefault();
      if (ALLOWED_EXTERNAL_PROTOCOLS.has(target.protocol)) {
        void shell.openExternal(url);
      }
    } catch {
      event.preventDefault();
    }
  });
}

function registerIpcHandlers(): void {
  ipcMain.on(IpcChannels.getBuildInfoSync, (event) => {
    event.returnValue = getBuildInfo();
  });

  ipcMain.on(IpcChannels.getSentryInitOptionsSync, (event) => {
    event.returnValue = getSentryInitOptions();
  });

  ipcMain.on(IpcChannels.getSettingsSync, (event) => {
    event.returnValue = getSettings();
  });

  ipcMain.handle(IpcChannels.updateSetting, (_event, payload: unknown) => {
    if (!payload || typeof payload !== "object") {
      return getSettings();
    }
    const { key, value } = payload as {
      key: keyof SettingsSnapshot;
      value: SettingsSnapshot[keyof SettingsSnapshot];
    };
    if (!(key in getSettings())) {
      return getSettings();
    }
    return updateSetting(key, value);
  });

  ipcMain.handle(
    IpcChannels.getSystemThemeVariant,
    (): SystemThemeVariant => currentThemeVariant()
  );

  ipcMain.handle(IpcChannels.openExternal, async (_event, url: unknown) => {
    if (typeof url !== "string") {
      return;
    }
    try {
      const parsed = new URL(url);
      if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
        await shell.openExternal(url);
      }
    } catch {
      // ignore malformed urls
    }
  });

  ipcMain.on(IpcChannels.rendererError, (_event, payload: unknown) => {
    // eslint-disable-next-line no-console
    console.error("[renderer]", payload);
  });

  ipcMain.handle(IpcChannels.openWindow, async (_event, kind: unknown) => {
    if (kind === "secondary") {
      await openSecondaryWindow();
    } else if (kind === "hud") {
      await openHudWindow();
    } else if (kind === "primary") {
      await openPrimaryWindow();
    }
  });

  ipcMain.on(IpcChannels.authSnapshotSync, (event) => {
    event.returnValue = getAuthSnapshot();
  });
  ipcMain.handle(IpcChannels.authGetToken, () => getAuthToken());
  ipcMain.handle(IpcChannels.authSignIn, () => beginSignIn());
  ipcMain.handle(IpcChannels.authSignOut, () => signOutAuth());
}

function broadcastThemeUpdates(): void {
  nativeTheme.on("updated", () => {
    const variant = currentThemeVariant();
    for (const win of BrowserWindow.getAllWindows()) {
      win.webContents.send(IpcChannels.systemThemeVariantUpdated, variant);
      applyTitleBarOverlayTheme(win);
    }
  });
}

type Kind = "primary" | "secondary" | "hud";

const windowsByKind = new Map<Kind, Set<BrowserWindow>>();

function registerWindow(kind: Kind, win: BrowserWindow): void {
  const set = windowsByKind.get(kind) ?? new Set<BrowserWindow>();
  set.add(win);
  windowsByKind.set(kind, set);
  win.once("closed", () => {
    set.delete(win);
  });
}

async function openKind(kind: Kind): Promise<BrowserWindow> {
  const win = await createWindow({ kind, harden: hardenContents });
  registerWindow(kind, win);
  attachLocalShortcuts(win);
  if (!app.isPackaged) {
    win.webContents.openDevTools({ mode: "detach" });
  }
  return win;
}

export function openPrimaryWindow(): Promise<BrowserWindow> {
  return openKind("primary");
}

export function openSecondaryWindow(): Promise<BrowserWindow> {
  return openKind("secondary");
}

export function openHudWindow(): Promise<BrowserWindow> {
  return openKind("hud");
}

function findWindow(kind: Kind): BrowserWindow | null {
  const set = windowsByKind.get(kind);
  if (!set) {
    return null;
  }
  for (const win of set) {
    if (!win.isDestroyed()) {
      return win;
    }
  }
  return null;
}

function toggleHudWindow(): void {
  const existing = findWindow("hud");
  if (existing) {
    if (existing.isVisible()) {
      existing.hide();
    } else {
      existing.show();
      existing.focus();
    }
  } else {
    void openHudWindow();
  }
}

const trayActions = {
  showPrimary: () => {
    const existing = findWindow("primary");
    if (existing) {
      existing.show();
      existing.focus();
    } else {
      void openPrimaryWindow();
    }
  },
  toggleHud: toggleHudWindow,
};

function applySettings(snapshot: SettingsSnapshot): void {
  nativeTheme.themeSource = snapshot.themeSource;
  if (process.platform !== "linux" && app.isPackaged) {
    app.setLoginItemSettings({ openAtLogin: snapshot.launchAtLogin });
  }
  if (snapshot.showInMenuBar) {
    createTray(trayActions);
  } else {
    destroyTray();
  }
}

function broadcastSettings(snapshot: SettingsSnapshot): void {
  for (const win of BrowserWindow.getAllWindows()) {
    win.webContents.send(IpcChannels.settingsChanged, snapshot);
  }
}

initSentry();

contextMenu({
  showInspectElement: !app.isPackaged,
  showSaveImageAs: true,
  showCopyImage: true,
  showSelectAll: true,
});

app.whenReady().then(() => {
  applyContentSecurityPolicy();
  session.defaultSession.setPermissionRequestHandler(
    (_contents, _permission, callback) => {
      callback(false);
    }
  );

  Menu.setApplicationMenu(
    buildApplicationMenu({
      openSecondary: () => {
        void openSecondaryWindow();
      },
      openHud: () => {
        void openHudWindow();
      },
    })
  );

  registerIpcHandlers();
  registerUpdaterIpc();
  broadcastThemeUpdates();
  registerGlobalShortcuts({ toggleHud: toggleHudWindow });
  applySettings(getSettings());
  if (getSettings().checkForUpdatesAutomatically) {
    initUpdater();
  }
  onSettingsChanged((snapshot) => {
    applySettings(snapshot);
    broadcastSettings(snapshot);
  });
  void openPrimaryWindow();

  const focusGate = createAuthFocusGate({
    initiallySignedIn: Boolean(getAuthSnapshot().isSignedIn),
    getWindows: () => BrowserWindow.getAllWindows(),
  });
  onAuthChanged((snapshot) => {
    for (const win of BrowserWindow.getAllWindows()) {
      win.webContents.send(IpcChannels.authChanged, snapshot);
    }
    focusGate(snapshot);
  });

  app.on("activate", () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      void openPrimaryWindow();
    }
  });
});

app.on("will-quit", () => {
  unregisterGlobalShortcuts();
  destroyTray();
});

app.on("web-contents-created", (_event, contents) => {
  hardenContents(contents);
});

app.on("window-all-closed", () => {
  if (process.platform !== "darwin") {
    app.quit();
  }
});

import { beforeEach, describe, expect, it, vi } from "vitest";
import { createAuthFocusGate, type FocusableWindow } from "../auth-focus-gate";

type WindowSpy = FocusableWindow & {
  show: ReturnType<typeof vi.fn>;
  focus: ReturnType<typeof vi.fn>;
};

function makeWindowSpy(): WindowSpy {
  return { show: vi.fn(), focus: vi.fn() } as WindowSpy;
}

describe("createAuthFocusGate", () => {
  let win: WindowSpy;
  let windows: FocusableWindow[];

  beforeEach(() => {
    win = makeWindowSpy();
    windows = [win];
  });

  it("focuses on signed-out → signed-in transition", () => {
    const gate = createAuthFocusGate({
      initiallySignedIn: false,
      getWindows: () => windows,
    });
    gate({ isSignedIn: true });
    expect(win.show).toHaveBeenCalledTimes(1);
    expect(win.focus).toHaveBeenCalledTimes(1);
  });

  it("does not focus on signed-in → signed-in (token refresh)", () => {
    const gate = createAuthFocusGate({
      initiallySignedIn: true,
      getWindows: () => windows,
    });
    gate({ isSignedIn: true });
    expect(win.show).not.toHaveBeenCalled();
    expect(win.focus).not.toHaveBeenCalled();
  });

  it("does not focus on signed-in → signed-out (sign-out)", () => {
    const gate = createAuthFocusGate({
      initiallySignedIn: true,
      getWindows: () => windows,
    });
    gate({ isSignedIn: false });
    expect(win.show).not.toHaveBeenCalled();
    expect(win.focus).not.toHaveBeenCalled();
  });

  it("focuses on re-sign-in after sign-out", () => {
    const gate = createAuthFocusGate({
      initiallySignedIn: false,
      getWindows: () => windows,
    });
    gate({ isSignedIn: true });
    gate({ isSignedIn: false });
    gate({ isSignedIn: true });
    expect(win.show).toHaveBeenCalledTimes(2);
    expect(win.focus).toHaveBeenCalledTimes(2);
  });

  it("focuses every window in the list, not just the first", () => {
    const win2 = makeWindowSpy();
    windows = [win, win2];
    const gate = createAuthFocusGate({
      initiallySignedIn: false,
      getWindows: () => windows,
    });
    gate({ isSignedIn: true });
    expect(win.show).toHaveBeenCalledTimes(1);
    expect(win2.show).toHaveBeenCalledTimes(1);
    expect(win.focus).toHaveBeenCalledTimes(1);
    expect(win2.focus).toHaveBeenCalledTimes(1);
  });

  it("calls getWindows at fire-time, not at gate-construction time", () => {
    const getWindows = vi.fn(() => windows);
    const gate = createAuthFocusGate({
      initiallySignedIn: false,
      getWindows,
    });
    expect(getWindows).not.toHaveBeenCalled();
    gate({ isSignedIn: true });
    expect(getWindows).toHaveBeenCalledTimes(1);
  });

  it("does not call getWindows for non-focusing transitions", () => {
    const getWindows = vi.fn(() => windows);
    const gate = createAuthFocusGate({
      initiallySignedIn: true,
      getWindows,
    });
    gate({ isSignedIn: false });
    gate({ isSignedIn: false });
    expect(getWindows).not.toHaveBeenCalled();
  });
});

export interface FocusableWindow {
  focus: () => void;
  show: () => void;
}

export interface AuthFocusGateOptions {
  getWindows: () => FocusableWindow[];
  initiallySignedIn: boolean;
}

/**
 * Tracks the signed-in transition so that only a false → true flip yanks
 * focus. Token refreshes (true → true) and sign-outs (true → false) are
 * ignored. Seeding `initiallySignedIn` from the current auth snapshot
 * prevents a false positive when the boot-time `emit(true)` arrives before
 * the subscriber.
 */
export function createAuthFocusGate(
  options: AuthFocusGateOptions
): (snapshot: { isSignedIn: boolean }) => void {
  let prev = options.initiallySignedIn;
  return (snapshot) => {
    const next = Boolean(snapshot.isSignedIn);
    if (!prev && next) {
      for (const win of options.getWindows()) {
        win.show();
        win.focus();
      }
    }
    prev = next;
  };
}

## Phase 3: ClientAuthBridge state machine + useEffect dep array

### Overview

Make `ClientAuthBridge` deterministic when Clerk reports signed-out, and stabilize the effect's dep array so it doesn't re-fire on every parent render.

### Changes Required

#### 1. `apps/app/src/app/(app)/(user)/(pending-not-allowed)/_components/client-auth-bridge.tsx`

**Gate the handshake with a `useRef` one-shot latch instead of fighting the dep array.**

Enumerating stable callables in the dep array (`buildPostCallback`, `buildRedirectUrl`, `jwtTemplate`) looks principled but is fragile in practice: both parents (`desktop-auth-client.tsx`, `cli-auth-client.tsx`) pass builders as inline arrow closures, so identity flips on every parent re-render. Today the parents are stateless and rarely re-render, but any future wrapping layout change, React 19 transition, or searchParams mutation would re-fire the effect mid-handshake — and `getToken()` would run again, potentially double-POSTing.

The handshake is *semantically* one-shot (one tab, one token, one POST). Make that explicit with a ref latch and you can cut the dep array to the two values that genuinely drive the state transition:

```ts
const didStart = useRef(false);

useEffect(() => {
  if (!isLoaded || didStart.current) {
    return;
  }
  if (!isSignedIn) {
    setStatus("error");
    didStart.current = true;
    return;
  }
  didStart.current = true;
  void (async () => {
    try {
      const token = await getToken(
        props.jwtTemplate ? { template: props.jwtTemplate } : undefined
      );
      if (!token) {
        setStatus("error");
        return;
      }
      // ... Phase 2's branching on props.mode ...
    } catch {
      setStatus("error");
    }
  })();
}, [isLoaded, isSignedIn]);
```

Notes:
- Latch is set **before** the async work starts, so an exception in the async block still bars re-entry.
- Dep array is `[isLoaded, isSignedIn]` only — no builder/searchParams/jwtTemplate identity concerns. The builder is read off `props` at call time, which is fine because the handshake runs exactly once.
- `isLoaded && !isSignedIn` resolves deterministically to `"error"` instead of idle "loading" (fix for #4).
- React 18/19 StrictMode double-invokes effects in dev; the second invocation sees `didStart.current === true` and bails, which is the correct behavior here (the first run already kicked off the handshake).
- Biome's `lint/correctness/useExhaustiveDependencies` rule will flag the missing deps (`props`, `getToken`, `searchParams`). Disable with a targeted inline comment — note this is the Biome rule path, not ESLint's `react-hooks/exhaustive-deps` (ultracite / biome is the only linter configured; ESLint comments will be ignored): `// biome-ignore lint/correctness/useExhaustiveDependencies: handshake is one-shot, latched by didStart.current — re-firing the effect would double-POST the token.`

### Success Criteria

#### Automated Verification:

- [ ] `pnpm --filter @lightfast/app typecheck` passes.
- [ ] `pnpm biome check apps/app/src/app/\\(app\\)/\\(user\\)/\\(pending-not-allowed\\)/_components/client-auth-bridge.tsx` is clean.

#### Manual Verification:

- [ ] In DevTools, sign out in another tab while `/desktop/auth` is open → the bridge flips from "Authenticating…" to "Authentication Failed" within one tick (not stuck in "loading").
- [ ] Open `/desktop/auth` in an incognito window with no Clerk session → renders "Authentication Failed" deterministically.
- [ ] Normal signed-in flow still works (happy path from Phase 2's manual checks).

