","export type MicrofrontendErrorType =
  | 'config'
  | 'packageJson'
  | 'vercelJson'
  | 'application'
  | 'unknown';

export type MicrofrontendErrorSubtype =
  | 'not_found'
  | 'inference_failed'
  | 'not_found_in_env'
  | 'invalid_asset_prefix'
  | 'invalid_main_path'
  | 'does_not_match_schema'
  | 'unable_to_read_file'
  | 'unsupported_validation_env'
  | 'unsupported_version'
  | 'invalid_path'
  | 'invalid_permissions'
  | 'invalid_syntax'
  | 'missing_microfrontend_config_path'
  | 'unsupported_operation';

// A mapping of error types to their subtypes.
interface TypeToSubtype {
  application:
    | 'invalid_asset_prefix'
    | 'invalid_path'
    | 'multiple_package_managers'
    | 'not_found';
  config:
    | 'conflicting_paths'
    | 'depcrecated_field'
    | 'does_not_match_schema'
    | 'invalid_main_path'
    | 'invalid_preview_deployment_suffix'
    | 'multiple_default_applications'
    | 'no_default_application'
    | 'not_found_in_env'
    | 'not_found'
    | 'inference_failed'
    | 'unable_to_read_file'
    | 'invalid_syntax'
    | 'invalid_permissions'
    | 'unsupported_operation'
    | 'unsupported_validation_env'
    | 'unsupported_version';
  packageJson:
    | 'missing_field_name'
    | 'unable_to_read_file'
    | 'invalid_permissions'
    | 'invalid_syntax';
  vercelJson:
    | 'missing_field_microfrontend_config_path'
    | 'unable_to_read_file'
    | 'invalid_permissions'
    | 'invalid_syntax';
  unknown: never;
}

export type MicrofrontendErrorSource =
  | '@vercel/microfrontends'
  | '@vercel/microfrontends/next'
  | 'fs'
  | 'ajv';

export interface MicrofrontendErrorOptions<T extends MicrofrontendErrorType> {
  cause?: unknown;
  source?: MicrofrontendErrorSource;
  type?: T;
  subtype?: TypeToSubtype[T];
}

interface HandleOptions {
  fileName?: string;
}

export class MicrofrontendError<
  T extends MicrofrontendErrorType = 'unknown',
> extends Error {
  public source: MicrofrontendErrorSource;
  public type: T;
  public subtype?: TypeToSubtype[T];

  constructor(message: string, opts?: MicrofrontendErrorOptions<T>) {
    super(message, { cause: opts?.cause });
    this.name = 'MicrofrontendsError';
    this.source = opts?.source ?? '@vercel/microfrontends';
    this.type = opts?.type ?? ('unknown' as T);
    this.subtype = opts?.subtype;
    Error.captureStackTrace(this, MicrofrontendError);
  }

  isKnown(): boolean {
    return this.type !== 'unknown';
  }

  isUnknown(): boolean {
    return !this.isKnown();
  }

  /**
   * Converts an error to a MicrofrontendsError.
   * @param original - The original error to convert.
   * @returns The converted MicrofrontendsError.
   */
  static convert(
    original: Error,
    opts?: HandleOptions,
  ): MicrofrontendError<MicrofrontendErrorType> {
    if (opts?.fileName) {
      const err = MicrofrontendError.convertFSError(original, opts.fileName);
      if (err) {
        return err;
      }
    }

    if (
      original.message.includes(
        'Code generation from strings disallowed for this context',
      )
    ) {
      return new MicrofrontendError(original.message, {
        type: 'config',
        subtype: 'unsupported_validation_env',
        source: 'ajv',
      });
    }

    // unknown catch-all
    return new MicrofrontendError(original.message);
  }

  static convertFSError(
    original: Error,
    fileName: string,
  ): MicrofrontendError<MicrofrontendErrorType> | null {
    if (original instanceof Error && 'code' in original) {
      if (original.code === 'ENOENT') {
        return new MicrofrontendError(`Could not find "${fileName}"`, {
          type: 'config',
          subtype: 'unable_to_read_file',
          source: 'fs',
        });
      }
      if (original.code === 'EACCES') {
        return new MicrofrontendError(
          `Permission denied while accessing "${fileName}"`,
          {
            type: 'config',
            subtype: 'invalid_permissions',
            source: 'fs',
          },
        );
      }
    }

    if (original instanceof SyntaxError) {
      return new MicrofrontendError(
        `Failed to parse "${fileName}": Invalid JSON format.`,
        {
          type: 'config',
          subtype: 'invalid_syntax',
          source: 'fs',
        },
      );
    }

    return null;
  }

  /**
   * Handles an unknown error and returns a MicrofrontendsError instance.
   * @param err - The error to handle.
   * @returns A MicrofrontendsError instance.
   */
  static handle(
    err: unknown,
    opts?: HandleOptions,
  ): MicrofrontendError<MicrofrontendErrorType> {
    if (err instanceof MicrofrontendError) {
      return err as MicrofrontendError<MicrofrontendErrorType>;
    }

    // handle Error instances
    if (err instanceof Error) {
      return MicrofrontendError.convert(err, opts);
    }

    // handle object errors
    if (typeof err === 'object' && err !== null) {
      if ('message' in err && typeof err.message === 'string') {
        return MicrofrontendError.convert(new Error(err.message), opts);
      }
    }

    return new MicrofrontendError('An unknown error occurred');
  }
}
","import { parse } from 'jsonc-parser';
import { MicrofrontendError } from '../../errors';
import { hashApplicationName } from '../../microfrontends/utils/hash-application-name';
import { type OverridesConfig, parseOverrides } from '../../overrides';
import type { Config } from '../../schema/types';
import { isDefaultApp } from '../../schema/utils/is-default-app';
import { MicrofrontendConfigClient } from '../client';
import type { ClientConfig } from '../client/types';
import { getConfigStringFromEnv } from '../utils/get-config-from-env';
import { ChildApplication, DefaultApplication } from './application';
import {
  DEFAULT_LOCAL_PROXY_PORT,
  MFE_LOCAL_PROXY_PORT_ENV,
} from './constants';
import {
  validateConfigDefaultApplication,
  validateConfigPaths,
} from './validation';

/**
 * A class to manage the microfrontends configuration.
 */
export class MicrofrontendConfigIsomorphic {
  config: Config;
  defaultApplication: DefaultApplication;
  childApplications: Record<string, ChildApplication> = {};
  overrides?: OverridesConfig;
  options?: Config['options'];

  private readonly serialized: {
    config: Config;
    overrides?: OverridesConfig;
  };

  constructor({
    config,
    overrides,
  }: {
    config: Config;
    overrides?: OverridesConfig;
  }) {
    // run validation on init
    MicrofrontendConfigIsomorphic.validate(config);

    const disableOverrides = config.options?.disableOverrides ?? false;
    this.overrides = overrides && !disableOverrides ? overrides : undefined;

    let defaultApplication: DefaultApplication | undefined;
    // create applications
    for (const [appId, appConfig] of Object.entries(config.applications)) {
      const appOverrides = !disableOverrides
        ? this.overrides?.applications[appId]
        : undefined;

      if (isDefaultApp(appConfig)) {
        defaultApplication = new DefaultApplication(appId, {
          app: appConfig,
          overrides: appOverrides,
        });
      } else {
        this.childApplications[appId] = new ChildApplication(appId, {
          app: appConfig,
          overrides: appOverrides,
        });
      }
    }

    // validate that this.defaultApplication is defined
    if (!defaultApplication) {
      throw new MicrofrontendError(
        'Could not find default application in microfrontends configuration',
        {
          type: 'application',
          subtype: 'not_found',
        },
      );
    }
    this.defaultApplication = defaultApplication;

    this.config = config;
    this.options = config.options;
    this.serialized = {
      config,
      overrides,
    };
  }

  static validate(config: string | Config): Config {
    // let this throw if it's not valid JSON
    const c = typeof config === 'string' ? (parse(config) as Config) : config;

    validateConfigPaths(c.applications);
    validateConfigDefaultApplication(c.applications);

    return c;
  }

  static fromEnv({
    cookies,
  }: {
    cookies?: { name: string; value: string }[];
  }): MicrofrontendConfigIsomorphic {
    return new MicrofrontendConfigIsomorphic({
      config: parse(getConfigStringFromEnv()) as Config,
      overrides: parseOverrides(cookies ?? []),
    });
  }

  isOverridesDisabled(): boolean {
    return this.options?.disableOverrides ?? false;
  }

  getConfig(): Config {
    return this.config;
  }

  getApplicationsByType(): {
    defaultApplication?: DefaultApplication;
    applications: ChildApplication[];
  } {
    return {
      defaultApplication: this.defaultApplication,
      applications: Object.values(this.childApplications),
    };
  }

  getChildApplications(): ChildApplication[] {
    return Object.values(this.childApplications);
  }

  getAllApplications(): (DefaultApplication | ChildApplication)[] {
    return [
      this.defaultApplication,
      ...Object.values(this.childApplications),
    ].filter(Boolean);
  }

  getApplication(name: string): DefaultApplication | ChildApplication {
    // check the default
    if (
      this.defaultApplication.name === name ||
      this.defaultApplication.packageName === name
    ) {
      return this.defaultApplication;
    }
    const app =
      this.childApplications[name] ||
      Object.values(this.childApplications).find(
        (child) => child.packageName === name,
      );
    if (!app) {
      throw new MicrofrontendError(
        `Could not find microfrontends configuration for application "${name}". If the name in package.json differs from your Vercel Project name, set the \`packageName\` field for the application in \`microfrontends.json\` to ensure that the configuration can be found locally.`,
        {
          type: 'application',
          subtype: 'not_found',
        },
      );
    }

    return app;
  }

  hasApplication(name: string): boolean {
    try {
      this.getApplication(name);
      return true;
    } catch {
      return false;
    }
  }

  getApplicationByProjectName(
    projectName: string,
  ): DefaultApplication | ChildApplication | undefined {
    // check the default
    if (this.defaultApplication.name === projectName) {
      return this.defaultApplication;
    }

    return Object.values(this.childApplications).find(
      (app) => app.name === projectName,
    );
  }

  /**
   * Returns the default application.
   */
  getDefaultApplication(): DefaultApplication {
    return this.defaultApplication;
  }

  /**
   * Returns the configured port for the local proxy.
   * Can be overridden via MFE_LOCAL_PROXY_PORT environment variable.
   */
  getLocalProxyPort(): number {
    // Check for port override via environment variable
    const portOverride = process.env[MFE_LOCAL_PROXY_PORT_ENV];
    if (portOverride) {
      const port = Number.parseInt(portOverride, 10);
      if (!Number.isNaN(port) && port > 0 && port < 65536) {
        return port;
      }
    }
    return this.config.options?.localProxyPort ?? DEFAULT_LOCAL_PROXY_PORT;
  }

